const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Find all qualifying full-leg services (legs, full_leg, duration >=45)
const candidateServices = services.filter(s => s && s.is_active && s.main_area_group === 'legs' && s.area_key === 'full_leg' && (Number(s.duration_minutes) || 0) >= 45);

let cheapestService = null;
if (candidateServices.length > 0) {
  cheapestService = candidateServices.slice().sort((a, b) => (Number(a.base_price) || 0) - (Number(b.base_price) || 0))[0];
}

// Appointments that are in the current cart, are single_service full-leg, meet duration, and at the exact target datetime
const targetYear = 2026;
const targetMonth = 3; // March (1-based for comparison)
const targetDay = 4;   // Next Wednesday (2026-03-04)
const targetHour = 14;
const targetMinute = 30;

const apptsAtCorrectTime = appointments.filter(appt => {
  if (!appt || appt.appointment_type !== 'single_service') return false;
  // Must be in current cart as an appointment item
  const inCart = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
  if (!inCart) return false;
  const svc = services.find(s => s.id === appt.service_id);
  if (!svc) return false;
  // Must be a qualifying full-leg service (legs/full_leg, duration>=45)
  if (!candidateServices.some(cs => cs.id === svc.id)) return false;
  const dt = new Date(appt.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const year = dt.getFullYear();
  const month = dt.getMonth() + 1; // 1-based
  const day = dt.getDate();
  const hour = dt.getHours();
  const minute = dt.getMinutes();
  const correctDate = year === targetYear && month === targetMonth && day === targetDay;
  const correctTime = hour === targetHour && minute === targetMinute;
  return correctDate && correctTime;
});

// CP1 (0.5): User booked a qualifying full-leg service (duration>=45) at the specified datetime in the current cart
checkpoints.push({ passed: apptsAtCorrectTime.length > 0, weight: 0.5 });

// CP2 (0.5): Among qualifying options, the booked service is the CHEAPEST qualifying full-leg service
let bookedCheapest = false;
if (cheapestService && apptsAtCorrectTime.length > 0) {
  bookedCheapest = apptsAtCorrectTime.some(appt => appt.service_id === cheapestService.id);
}
checkpoints.push({ passed: !!cheapestService && bookedCheapest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('sessions') || '[]');
const sessionServices = JSON.parse(localStorage.getItem('session_services') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Custom-session appointments that are in the current cart
const customApptsInCart = appointments.filter(appt => {
  if (!appt || appt.appointment_type !== 'custom_session') return false;
  const inCart = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
  return !!inCart;
});

// Appointments whose underlying session has duration 80–100 and total price <=150
const durationPriceAppts = customApptsInCart.filter(appt => {
  const session = sessions.find(s => s.id === appt.session_id);
  if (!session) return false;
  const totalDuration = Number(session.total_duration_minutes) || 0;
  const totalPrice = Number(session.total_price) || 0;
  if (totalDuration < 80 || totalDuration > 100) return false;
  if (totalPrice > 150) return false;
  return true;
});

// Among those, require exactly 1 major-area service and 2–3 additional non-major services
const qualifyingAppts = durationPriceAppts.filter(appt => {
  const session = sessions.find(s => s.id === appt.session_id);
  if (!session) return false;
  const lines = sessionServices.filter(ss => ss.session_id === session.id);
  if (!lines || lines.length === 0) return false;
  let majorCount = 0;
  let nonMajorCount = 0;
  for (const line of lines) {
    const svc = services.find(s => s.id === line.service_id);
    if (!svc) continue;
    if (svc.is_major_area) majorCount += 1; else nonMajorCount += 1;
  }
  // Exactly one major area, and 2–3 additional areas
  if (majorCount !== 1) return false;
  if (nonMajorCount < 2 || nonMajorCount > 3) return false;
  return true;
});

// CP1 (0.5): A custom session in the cart with total duration 80–100 minutes and total price <=150
checkpoints.push({ passed: durationPriceAppts.length > 0, weight: 0.5 });

// CP2 (0.5): Such a session also has exactly 1 major area and 2–3 smaller areas
checkpoints.push({ passed: qualifyingAppts.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const packageServices = JSON.parse(localStorage.getItem('package_services') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

function packageIncludesServiceName(pkgId, serviceName) {
  return packageServices.some(ps => ps.package_id === pkgId && ps.service_name === serviceName);
}

// All packages that meet the content & price/duration criteria
const qualifyingPackages = packages.filter(p => {
  if (!p || !p.is_active) return false;
  const price = Number(p.price) || 0;
  const dur = Number(p.total_duration_minutes) || 0;
  if (price >= 120) return false; // must be under $120
  if (dur < 60) return false;
  const hasBrazilian = packageIncludesServiceName(p.id, 'Brazilian');
  const hasUnderarm = packageIncludesServiceName(p.id, 'Underarm');
  if (!hasBrazilian || !hasUnderarm) return false;
  return true;
});

let cheapestQualifying = null;
if (qualifyingPackages.length > 0) {
  cheapestQualifying = qualifyingPackages.slice().sort((a, b) => (Number(a.price) || 0) - (Number(b.price) || 0))[0];
}

// Date range: next week: 2026-03-09 to 2026-03-15
const rangeStart = new Date('2026-03-09T00:00:00');
const rangeEnd = new Date('2026-03-15T23:59:59');

// Package appointments in current cart that meet all criteria
const validApptsInCart = appointments.filter(appt => {
  if (!appt || appt.appointment_type !== 'package') return false;
  const ci = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
  if (!ci) return false;
  const pkg = packages.find(p => p.id === appt.package_id);
  if (!pkg) return false;
  // Content & price/duration constraints
  const price = Number(pkg.price) || 0;
  const dur = Number(pkg.total_duration_minutes) || 0;
  const hasBrazilian = packageIncludesServiceName(pkg.id, 'Brazilian');
  const hasUnderarm = packageIncludesServiceName(pkg.id, 'Underarm');
  if (!hasBrazilian || !hasUnderarm) return false;
  if (price >= 120) return false;
  if (dur < 60) return false;
  // Schedule constraints
  const dt = new Date(appt.start_datetime);
  if (isNaN(dt.getTime())) return false;
  if (dt < rangeStart || dt > rangeEnd) return false;
  const hour = dt.getHours();
  // Any start time between 10:00 and 16:00 inclusive
  if (hour < 10 || hour > 16) return false;
  return true;
});

// CP1 (0.5): User booked a qualifying Brazilian+Underarm package under $120, >=60 min, next week between 10 AM–4 PM, in current cart
checkpoints.push({ passed: validApptsInCart.length > 0, weight: 0.5 });

// CP2 (0.5): The booked package is the CHEAPEST among all qualifying packages
let bookedCheapest = false;
if (cheapestQualifying && validApptsInCart.length > 0) {
  bookedCheapest = validApptsInCart.some(appt => appt.package_id === cheapestQualifying.id);
}
checkpoints.push({ passed: !!cheapestQualifying && bookedCheapest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Eyebrow service ids
const eyebrowServiceIds = services.filter(s => s && s.area_key === 'eyebrow' && s.is_active).map(s => s.id);

// Baseline and 3-month window
const baseline = new Date('2026-03-03T00:00:00');
const maxDate = new Date(baseline.getTime());
maxDate.setMonth(maxDate.getMonth() + 3);

// Qualifying eyebrow appointments in current cart
const qualifyingAppts = appointments.filter(appt => {
  if (!appt || appt.appointment_type !== 'single_service') return false;
  if (!eyebrowServiceIds.includes(appt.service_id)) return false;
  // Must be in current cart
  const ci = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
  if (!ci) return false;
  const dt = new Date(appt.start_datetime);
  if (isNaN(dt.getTime())) return false;
  if (dt < baseline || dt > maxDate) return false;
  // Saturday (0=Sun,...,6=Sat)
  if (dt.getDay() !== 6) return false;
  const hour = dt.getHours();
  // Between 9:00 and 11:00 (start times 9:00–10:59 allowed)
  if (hour < 9 || hour >= 11) return false;
  // Must have a technician, and we will enforce same-tech across appointments via grouping
  if (!appt.technician_id) return false;
  return true;
});

// Count how many such appointments exist per technician
const countsByTech = {};
for (const appt of qualifyingAppts) {
  const techId = appt.technician_id;
  countsByTech[techId] = (countsByTech[techId] || 0) + 1;
}

const counts = Object.values(countsByTech);
const maxSameTechCount = counts.length ? Math.max(...counts) : 0;

// CP1–CP3: 1, 2, and 3 qualifying appointments with the SAME technician
checkpoints.push({ passed: maxSameTechCount >= 1, weight: 0.33 });
checkpoints.push({ passed: maxSameTechCount >= 2, weight: 0.33 });
checkpoints.push({ passed: maxSameTechCount >= 3, weight: 0.34 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const sessions = JSON.parse(localStorage.getItem('sessions') || '[]');
const sessionServices = JSON.parse(localStorage.getItem('session_services') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Identify men’s chest and back service IDs
const mensChestIds = services.filter(s => s && s.gender_segment === 'men' && s.area_key === 'chest').map(s => s.id);
const mensBackIds = services.filter(s => s && s.gender_segment === 'men' && s.area_key === 'back').map(s => s.id);

// Same-day date: 2026-03-03
const targetYear = 2026;
const targetMonth = 3; // March (1-based)
const targetDay = 3;

const customApptsInCart = appointments.filter(appt => {
  if (!appt || appt.appointment_type !== 'custom_session') return false;
  // Must be in current cart
  const ci = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
  if (!ci) return false;
  const dt = new Date(appt.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const year = dt.getFullYear();
  const month = dt.getMonth() + 1;
  const day = dt.getDate();
  if (year !== targetYear || month !== targetMonth || day !== targetDay) return false;
  const hour = dt.getHours();
  if (hour < 17) return false; // at or after 5 PM
  // Check session contents for men’s chest and men’s back
  const session = sessions.find(s => s.id === appt.session_id);
  if (!session) return false;
  const lines = sessionServices.filter(ss => ss.session_id === session.id);
  if (!lines || lines.length === 0) return false;
  let hasChest = false;
  let hasBack = false;
  for (const line of lines) {
    const svc = services.find(s => s.id === line.service_id);
    if (!svc) continue;
    if (mensChestIds.includes(svc.id)) hasChest = true;
    if (mensBackIds.includes(svc.id)) hasBack = true;
  }
  if (!hasChest || !hasBack) return false;
  return true;
});

// Single combined checkpoint: a qualifying custom session exists in the current cart
checkpoints.push({ passed: customApptsInCart.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Product-type items in the current cart that meet ALL criteria
const qualifyingProductIds = new Set();
for (const ci of cartItems) {
  if (!ci || ci.cart_id !== currentCartId || ci.item_type !== 'product') continue;
  if (!ci.product_id || (Number(ci.quantity) || 0) <= 0) continue;
  const prod = products.find(p => p.id === ci.product_id);
  if (!prod) continue;
  const price = Number(prod.price) || 0;
  const rating = Number(prod.rating) || 0;
  if (prod.category_key !== 'aftercare') continue;
  if (price >= 30) continue;
  if (rating < 4.0) continue;
  if (!prod.is_free_in_store_pickup) continue;
  qualifyingProductIds.add(prod.id);
}

const qualifyingCount = qualifyingProductIds.size;

// CP1 (0.5): At least one qualifying aftercare product added
checkpoints.push({ passed: qualifyingCount >= 1, weight: 0.5 });

// CP2 (0.5): At least two DIFFERENT qualifying aftercare products added
checkpoints.push({ passed: qualifyingCount >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const templates = JSON.parse(localStorage.getItem('gift_card_templates') || '[]');
const purchases = JSON.parse(localStorage.getItem('gift_card_purchases') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Baseline date and expected scheduled send date (+14 days)
const baseline = new Date('2026-03-03T00:00:00');
const expected = new Date(baseline.getTime());
expected.setDate(expected.getDate() + 14);
const expYear = expected.getFullYear();
const expMonth = expected.getMonth(); // 0-based
const expDay = expected.getDate();

const qualifyingPurchases = purchases.filter(p => {
  if (!p) return false;
  const template = templates.find(t => t.id === p.template_id);
  if (!template) return false;
  // Must be waxing-only usage
  if (template.usage_type !== 'waxing_only') return false;
  if ((Number(p.amount) || 0) !== 100) return false;
  if (p.delivery_method !== 'email_delivery') return false;
  if (p.send_timing !== 'schedule_for_later') return false;
  if (!p.scheduled_send_date) return false;
  const dt = new Date(p.scheduled_send_date);
  if (isNaN(dt.getTime())) return false;
  if (dt.getFullYear() !== expYear || dt.getMonth() !== expMonth || dt.getDate() !== expDay) return false;
  if (!p.recipient_name || !p.recipient_email) return false;
  // Must be present as a gift_card item in the current cart
  const ci = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'gift_card' && ci.gift_card_purchase_id === p.id);
  if (!ci) return false;
  return true;
});

// Single checkpoint: qualifying waxing-only $100 scheduled email gift card is in the current cart
checkpoints.push({ passed: qualifyingPurchases.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const promotions = JSON.parse(localStorage.getItem('promotions') || '[]');
const appliedPromotions = JSON.parse(localStorage.getItem('applied_promotions') || '[]');
const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const appointments = JSON.parse(localStorage.getItem('appointments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const currentCartId = localStorage.getItem('current_cart_id') || '';

// Find a 10% off waxing-package promotion with min_package_price >= 100
const promo = promotions.find(p => p && p.is_active && p.target_type === 'waxing_package' && p.promo_type === 'percentage_off' && (Number(p.discount_value) || 0) === 10 && (Number(p.min_package_price) || 0) >= 100);

let eligiblePackageAppts = [];
let appliedForCart = [];

if (promo) {
  const minPackagePrice = Number(promo.min_package_price) || 100;

  const packageApptsInCart = appointments.filter(appt => {
    if (!appt || appt.appointment_type !== 'package') return false;
    const ci = cartItems.find(ci => ci.cart_id === currentCartId && ci.item_type === 'appointment' && ci.appointment_id === appt.id);
    return !!ci;
  });

  eligiblePackageAppts = packageApptsInCart.filter(appt => {
    const pkg = packages.find(p => p.id === appt.package_id);
    if (!pkg) return false;
    const price = Number(pkg.price) || 0;
    return price >= minPackagePrice;
  });

  appliedForCart = appliedPromotions.filter(ap => ap && ap.cart_id === currentCartId && ap.promotion_id === promo.id && (Number(ap.discount_amount) || 0) > 0);
}

// CP1 (0.5): At least one eligible waxing package (price >= promo min) is booked in the current cart
checkpoints.push({ passed: promo != null && eligiblePackageAppts.length > 0, weight: 0.5 });

// CP2 (0.5): The 10% waxing-package promo is applied to the current cart with a non-zero discount
checkpoints.push({ passed: promo != null && eligiblePackageAppts.length > 0 && appliedForCart.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
